import { createContext, useContext, useEffect, useState, useMemo, useCallback, type ReactNode } from 'react';
import { UserManager, type User } from 'oidc-client-ts';
import { configService } from '../services/config.service';
import { oidcConfigService } from '../services/oidc.config';
import { setupAuthInterceptor, setGlobalUserManager } from '../services/auth.interceptor';
import { loginService } from '../services/login.service';
import { HeaderConfigProvider } from './HeaderConfigContext';
import { Header } from '../components/Header';
import type { AuthConfig } from '../types';

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (issuer: string, clientId: string, redirectUri: string) => Promise<void>;
  logout: () => Promise<void>;
  getUserManager: () => UserManager | null;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

interface AuthProviderProps {
  config: AuthConfig;
children: ReactNode;
    
}

export const AuthProvider = ({ config, children }: AuthProviderProps) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [userManager, setUserManager] = useState<UserManager | null>(null);

  useEffect(() => {
    configService.setConfig(config);
  }, [config]);

  // Setup interceptor early, before any async operations
  useEffect(() => {
    setupAuthInterceptor();
  }, []);

  const login = useCallback(async (issuer: string, clientId: string, redirectUri: string) => {
    await loginService.login(issuer, clientId, redirectUri);
    // Update user state after login
    const manager = loginService.getUserManager();
    if (manager) {
      setUserManager(manager);
      const user = await manager.getUser();
      if (user) {
        setUser(user);
        if (user.access_token) {
          sessionStorage.setItem('access_token', user.access_token);
        }
      }
    }
  }, []);

  useEffect(() => {
    const initializeAuth = async () => {
      try {
        // Check if we're in the OAuth callback - skip discovery loading there
        const inCallback = window.location.pathname.includes('/lib-auth-oauth-callback');
        
        if (!inCallback) {
          // Load discovery document (like Angular's APP_INITIALIZER)
          await loginService.loadDiscoveryDocument();
        }
        
        // Get or create UserManager
        let manager = loginService.getUserManager();
        
        // If no manager exists, try to create one from stored issuer
        if (!manager) {
          const issuer = sessionStorage.getItem('issuer') ?? config.default_issuer;
          const clientId = config.clientId;
          const url = new URL(window.location.href);
          const baseUri = url.host;
          const proto = url.protocol;
          const redirectUri = `${proto}//${baseUri}/lib-auth-oauth-callback`;
          const oidcConfig = oidcConfigService.configOptions(issuer, clientId, redirectUri);
          manager = new UserManager(oidcConfig);
          loginService.setUserManager(manager);
        }
        
        if (manager) {
          setUserManager(manager);
          setGlobalUserManager(manager);

          // Check if user is already logged in (from storage)
          // Store token in sessionStorage immediately to prevent 401 errors during initialization
          const currentUser = await manager.getUser();
          if (currentUser && currentUser.access_token) {
            setUser(currentUser);
            // Store token immediately - this ensures interceptor has access to it
            sessionStorage.setItem('access_token', currentUser.access_token);
          } else {
            // Even if getUser() returns null, check sessionStorage for existing token
            // This handles the case where token exists but UserManager hasn't loaded it yet
            const existingToken = sessionStorage.getItem('access_token');
            if (existingToken && !currentUser) {
              // Token exists but user not loaded - try to get user again
              try {
                const user = await manager.getUser();
                if (user && user.access_token) {
                  setUser(user);
                  sessionStorage.setItem('access_token', user.access_token);
                }
              } catch (error) {
                // If getUser fails, at least we have the token in sessionStorage
                console.warn('[AuthContext] Failed to get user, but token exists in sessionStorage');
              }
            }
          }

          // Handle silent refresh
          manager.events.addUserLoaded((loadedUser) => {
            setUser(loadedUser);
            if (loadedUser.access_token) {
              sessionStorage.setItem('access_token', loadedUser.access_token);
            }
          });

          manager.events.addUserSignedOut(() => {
            setUser(null);
            setGlobalUserManager(null);
          });
        }

        // Setup HTTP interceptor
        setupAuthInterceptor();
      } catch (error) {
        console.error('Auth initialization error:', error);
      } finally {
        setIsLoading(false);
      }
    };

    void initializeAuth();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [config]);


  const logout = useCallback(async () => {
    await loginService.logout();
    setUser(null);
    setUserManager(null);
    setGlobalUserManager(null);
  }, []);

  const getUserManager = useCallback(() => {
    return userManager || loginService.getUserManager();
  }, [userManager]);

  // Ensure context value is always defined, even during initialization
  const value: AuthContextType = {
    user,
    isAuthenticated: !!user && !!user.access_token,
    isLoading,
    login,
    logout,
    getUserManager,
  };

  // Use useMemo to ensure stable context value reference
  // This prevents unnecessary re-renders and context errors
  const contextValue = useMemo(() => value, [user, isLoading, login, logout, getUserManager]);

  return (
    <AuthContext.Provider value={contextValue}>
      <HeaderConfigProvider>
        <Header />
        {children}
      </HeaderConfigProvider>
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

