import { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { configService } from '../services/config.service';
import { loginService } from '../services/login.service';
import type { SessionSchema, UserAccount } from '../types';

export const UserProfile = () => {
  const { getUserManager, isLoading } = useAuth();
  
  // Check if user is logged in (matching Angular's isLoggedIn logic)
  const isLoggedIn = () => {
    return loginService.hasValidAccessToken() || !!sessionStorage.getItem('access_token');
  };
  const [formData, setFormData] = useState<UserAccount>({
    username: '',
    email: '',
    firstName: '',
    lastName: '',
  });
  const [tabStatus, setTabStatus] = useState<'Signing In' | 'Device Activity' | 'Linked Accounts'>('Signing In');
  const [passwordDetails, setPasswordDetails] = useState(false);
  const [passwordDate, setPasswordDate] = useState('');
  const [otpDetails, setOtpDetails] = useState(false);
  const [otpDate, setOtpDate] = useState('');
  const [sessions, setSessions] = useState<SessionSchema[]>([]);
  const [collapsed, setCollapsed] = useState<boolean[]>([]);
  const [requiredFields, setRequiredFields] = useState<string[]>([]);
  const [readOnlyFields, setReadOnlyFields] = useState<string[]>([]);

  useEffect(() => {
    // Wait for auth to finish initializing before making API calls
    // This prevents 401 errors on page reload
    if (isLoading) {
      return;
    }

    // Match Angular's ngOnInit behavior: check token directly, not just isAuthenticated
    if (isLoggedIn()) {
      populateFormFromServer();
      void getPasswordAndOTPDetails();
      void getDeviceDetails();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isLoading]); // Include isLoading to wait for auth init

  const populateFormFromServer = async () => {
    const issuer = sessionStorage.getItem('issuer');
    if (issuer) {
      try {
        // Convert full URL to relative path for proxy (e.g., http://localhost:8080/realms/... -> /realms/...)
        const accountUrl = issuer.startsWith('http') 
          ? issuer.replace(/^https?:\/\/[^/]+/, '') + '/account'
          : `${issuer}/account`;
        
        const response = await axios.get<UserAccount>(accountUrl);
        setFormData({
          username: response.data.username,
          email: response.data.email,
          firstName: response.data.firstName,
          lastName: response.data.lastName || '',
        });
        
        if (response.data.userProfileMetadata) {
          const required: string[] = [];
          const readOnly: string[] = [];
          response.data.userProfileMetadata.attributes.forEach((attr) => {
            if (attr.required) required.push(attr.name);
            if (attr.readOnly) readOnly.push(attr.name);
          });
          setRequiredFields(required);
          setReadOnlyFields(readOnly);
        }
      } catch (error) {
        console.error('Error fetching user data:', error);
      }
    }
  };

  const onSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const issuer = sessionStorage.getItem('issuer');
    if (issuer) {
      try {
        // Convert full URL to relative path for proxy
        const accountUrl = issuer.startsWith('http') 
          ? issuer.replace(/^https?:\/\/[^/]+/, '') + '/account/'
          : `${issuer}/account/`;
        
        await axios.post(accountUrl, formData);
        window.location.reload();
      } catch (error) {
        console.error('Error saving user data:', error);
      }
    }
  };

  const handleInputChange = (field: keyof UserAccount, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const getPasswordAndOTPDetails = async () => {
    const issuer = sessionStorage.getItem('issuer');
    if (!issuer) return;

    try {
      // Convert full URL to relative path for proxy
      const credentialsUrl = issuer.startsWith('http') 
        ? issuer.replace(/^https?:\/\/[^/]+/, '') + '/account/credentials'
        : `${issuer}/account/credentials`;
      
      const response = await axios.get(credentialsUrl);
      const data = response.data as Array<{
        userCredentialMetadatas: Array<{
          credential: { createdDate: number };
        }>;
      }>;

      if (data[0]?.userCredentialMetadatas?.[0]) {
        const timestampDate = data[0].userCredentialMetadatas[0].credential.createdDate;
        setPasswordDate(new Date(timestampDate).toString().slice(0, -22));
        setPasswordDetails(true);
      }

      if (data[1]?.userCredentialMetadatas?.[0]) {
        const otpTimestamp = data[1].userCredentialMetadatas[0].credential.createdDate;
        setOtpDate(new Date(otpTimestamp).toString().slice(0, -22));
        setOtpDetails(true);
      }
    } catch (error) {
      console.error('Error fetching password/OTP details:', error);
    }
  };

  const getDeviceDetails = async () => {
    const issuer = sessionStorage.getItem('issuer');
    if (!issuer) return;

    try {
      // Convert full URL to relative path for proxy
      const devicesUrl = issuer.startsWith('http') 
        ? issuer.replace(/^https?:\/\/[^/]+/, '') + '/account/sessions/devices'
        : `${issuer}/account/sessions/devices`;
      
      const response = await axios.get(devicesUrl);
      const deviceSessions: SessionSchema[] = [];
      let hasCurrentSession = false;

      (response.data as Array<{
        os: string;
        sessions: Array<{
          browser: string;
          current: boolean;
          ipAddress: string;
          started: number;
          lastAccess: number;
          expires: number;
          clients: Array<{ clientName: string }>;
          id: string;
        }>;
      }>).forEach((element) => {
        element.sessions.forEach((session) => {
          const individualSession: SessionSchema = {
            device: `${element.os} / ${session.browser}`,
            current_session: session.current,
            ip: session.ipAddress,
            started: new Date(session.started * 1000).toString().slice(0, -22),
            last_accessed: new Date(session.lastAccess * 1000).toString().slice(0, -22),
            expires: new Date(session.expires * 1000).toString().slice(0, -22),
            clients: session.clients.map((c) => c.clientName),
            id: session.id,
          };
          if (session.current) {
            hasCurrentSession = true;
          }
          deviceSessions.push(individualSession);
        });
      });

      deviceSessions.sort((_a, b) => (b.current_session ? 1 : -1));
      setSessions(deviceSessions);
      setCollapsed(new Array(deviceSessions.length).fill(true).map((_, i) => i !== 0));

      if (!hasCurrentSession) {
        const manager = getUserManager();
        if (manager) {
          await manager.signoutRedirect();
          sessionStorage.clear();
          localStorage.clear();
          window.location.href = '/';
        }
      }
    } catch (error) {
      console.error('Error fetching device details:', error);
    }
  };

  const changePasswordUrl = () => {
    const issuer = sessionStorage.getItem('issuer');
    const clientId = configService.clientId;
    const url = new URL(location.href);
    return `${issuer}/protocol/openid-connect/auth?client_id=${clientId}&redirect_uri=${url.protocol}//${url.host}/lib-auth-oauth-callback&response_type=code&scope=openid&kc_action=UPDATE_PASSWORD`;
  };

  const twoFactorAuthorizationUrl = () => {
    const issuer = sessionStorage.getItem('issuer');
    const clientId = configService.clientId;
    const url = new URL(location.href);
    return `${issuer}/protocol/openid-connect/auth?client_id=${clientId}&redirect_uri=${url.protocol}//${url.host}/lib-auth-oauth-callback&response_type=code&scope=openid&kc_action=CONFIGURE_TOTP`;
  };

  const toggleCollapse = (index: number) => {
    const newCollapsed = [...collapsed];
    for (let i = 0; i < sessions.length; i++) {
      if (i !== index) {
        newCollapsed[i] = true;
      }
    }
    newCollapsed[index] = !newCollapsed[index];
    setCollapsed(newCollapsed);
  };

  const reloadPage = () => {
    window.location.reload();
  };

  const signOutOfRequestedSession = async (index: number) => {
    const toDeleteSession = sessions[index];
    if (toDeleteSession.current_session === true) {
      const manager = getUserManager();
      if (manager) {
        await manager.signoutRedirect();
        sessionStorage.clear();
        localStorage.clear();
        window.location.href = '/';
      }
    } else {
      const issuer = sessionStorage.getItem('issuer');
      if (issuer) {
        try {
          // Convert full URL to relative path for proxy
          const deleteSessionUrl = issuer.startsWith('http') 
            ? issuer.replace(/^https?:\/\/[^/]+/, '') + `/account/sessions/${toDeleteSession.id}`
            : `${issuer}/account/sessions/${toDeleteSession.id}`;
          
          await axios.delete(deleteSessionUrl);
          window.location.reload();
        } catch (error) {
          console.error('Error signing out of session:', error);
        }
      }
    }
  };

  // Match Angular's *ngIf="isLoggedIn()" check
  if (!isLoggedIn()) {
    return null;
  }

  return (
    <div className="flex flex-col items-center gap-6">
      <div className="flex flex-col w-2/3 gap-6 mt-8">
        <div className="flex flex-col gap-6 items-start">
          <div className="flex items-start gap-2">
            <div className="flex justify-center items-center p-2 border rounded-lg border-frame-bg-300">
              <img className="self-stretch" src="assets/user-icon.svg" alt="user" />
            </div>
            <div className="flex flex-col justify-center items-start text-color-font-600 gap-1">
              <span className="text-lg/[18px] font-medium">Personal Info</span>
              <span className="text-sm font-normal">Manage your basic Information</span>
            </div>
          </div>
          <div className="grid gap-4 w-full items-center">
            <form onSubmit={onSave}>
              <div className="flex gap-4 justify-center items-start self-stretch">
                <div className="flex flex-col basis-1/2 gap-1 items-start self-stretch">
                  <label className="flex self-stretch items-center text-color-font-600 text-sm font-medium" htmlFor="username">
                    Username
                    {requiredFields.includes('username') && (
                      <span className="required text-new-red-100 font-medium text-sm">&nbsp;*</span>
                    )}
                  </label>
                  <div
                    className={`flex py-[9px] px-[13px] gap-1 border border-color-font-300 rounded-md w-full ${
                      readOnlyFields.includes('username')
                        ? 'bg-frame-bg-300 cursor-not-allowed'
                        : 'bg-frame-bg-100 shadow-sm'
                    }`}
                  >
                    <input
                      className={`placeholder:text-color-font-400 text-sm font-normal w-full focus:outline-none text-color-font-600 ${
                        readOnlyFields.includes('username')
                          ? 'bg-frame-bg-300 cursor-not-allowed'
                          : 'bg-frame-bg-100'
                      }`}
                      type="text"
                      placeholder="Enter Username"
                      value={formData.username}
                      onChange={(e) => handleInputChange('username', e.target.value)}
                      readOnly={readOnlyFields.includes('username')}
                      required={requiredFields.includes('username')}
                    />
                  </div>
                </div>
                <div className="flex flex-col basis-1/2 gap-1 items-start self-stretch">
                  <label className="flex self-stretch items-center text-color-font-600 text-sm font-medium" htmlFor="email">
                    Email ID
                    {requiredFields.includes('email') && (
                      <span className="required text-new-red-100 font-medium text-sm">&nbsp;*</span>
                    )}
                  </label>
                  <div
                    className={`flex py-[9px] px-[13px] gap-1 border border-color-font-300 rounded-md w-full ${
                      readOnlyFields.includes('email')
                        ? 'bg-frame-bg-300 cursor-not-allowed'
                        : 'bg-frame-bg-100 shadow-sm'
                    }`}
                  >
                    <input
                      className={`placeholder:text-color-font-400 text-sm font-normal w-full focus:outline-none text-color-font-600 ${
                        readOnlyFields.includes('email')
                          ? 'bg-frame-bg-300 cursor-not-allowed'
                          : 'bg-frame-bg-100'
                      }`}
                      type="email"
                      placeholder="Enter Email ID"
                      value={formData.email}
                      onChange={(e) => handleInputChange('email', e.target.value)}
                      readOnly={readOnlyFields.includes('email')}
                      required={requiredFields.includes('email')}
                    />
                  </div>
                </div>
              </div>
              <div className="flex gap-4 justify-center items-start self-stretch mt-4">
                <div className="flex flex-col basis-1/2 gap-1 items-start self-stretch">
                  <label className="flex self-stretch items-center text-color-font-600 text-sm font-medium" htmlFor="firstName">
                    First Name
                    {requiredFields.includes('firstName') && (
                      <span className="required text-new-red-100 font-medium text-sm">&nbsp;*</span>
                    )}
                  </label>
                  <div
                    className={`flex py-[9px] px-[13px] gap-1 border border-color-font-300 rounded-md w-full ${
                      readOnlyFields.includes('firstName')
                        ? 'bg-frame-bg-300 cursor-not-allowed'
                        : 'bg-frame-bg-100 shadow-sm'
                    }`}
                  >
                    <input
                      className={`placeholder:text-color-font-400 text-sm font-normal w-full focus:outline-none text-color-font-600 ${
                        readOnlyFields.includes('firstName')
                          ? 'bg-frame-bg-300 cursor-not-allowed'
                          : 'bg-frame-bg-100'
                      }`}
                      type="text"
                      placeholder="Enter Firstname"
                      value={formData.firstName}
                      onChange={(e) => handleInputChange('firstName', e.target.value)}
                      readOnly={readOnlyFields.includes('firstName')}
                      required={requiredFields.includes('firstName')}
                    />
                  </div>
                </div>
                <div className="flex flex-col basis-1/2 gap-1 items-start self-stretch">
                  <label className="flex self-stretch items-center text-color-font-600 text-sm font-medium" htmlFor="lastName">
                    Last Name
                    {requiredFields.includes('lastName') && (
                      <span className="required text-new-red-100 font-medium text-sm">&nbsp;*</span>
                    )}
                  </label>
                  <div
                    className={`flex py-[9px] px-[13px] gap-1 border border-color-font-300 focus:border-primary-brand-200 rounded-md w-full ${
                      readOnlyFields.includes('lastName')
                        ? 'bg-frame-bg-300 cursor-not-allowed'
                        : 'bg-frame-bg-100 shadow-sm'
                    }`}
                  >
                    <input
                      className={`placeholder:text-color-font-400 text-sm font-normal w-full focus:outline-none text-color-font-600 ${
                        readOnlyFields.includes('lastName')
                          ? 'bg-frame-bg-300 cursor-not-allowed'
                          : 'bg-frame-bg-100'
                      }`}
                      type="text"
                      placeholder="Enter Lastname"
                      value={formData.lastName}
                      onChange={(e) => handleInputChange('lastName', e.target.value)}
                      readOnly={readOnlyFields.includes('lastName')}
                    />
                  </div>
                </div>
              </div>
            </form>
          </div>
        </div>
        <div className="grid py-4 items-start self-stretch gap-6">
          <div className="flex items-center gap-2 self-stretch">
            <div className="flex justify-center items-center p-2 border rounded-lg border-frame-bg-300">
              <img src="assets/account-summary.svg" alt="account" />
            </div>
            <div className="flex">
              <span className="font-medium text-color-font-600 text-lg/[18px]">Account Summary</span>
            </div>
          </div>
          <div className="grid items-start self-stretch gap-4">
            <div className="flex self-stretch border-b border-frame-bg-300 gap-8">
              <button
                className={`flex flex-col text-sm px-1 pb-4 font-medium ${
                  tabStatus === 'Signing In'
                    ? 'text-delhivery-color-100 border-delhivery-color-100 border-b-2'
                    : 'text-color-font-600'
                }`}
                onClick={() => setTabStatus('Signing In')}
              >
                Signing In
              </button>
              <button
                className={`flex flex-col text-sm px-1 pb-4 font-medium ${
                  tabStatus === 'Device Activity'
                    ? 'text-delhivery-color-100 border-delhivery-color-100 border-b-2'
                    : 'text-color-font-600'
                }`}
                onClick={() => setTabStatus('Device Activity')}
              >
                Device Activity
              </button>
            </div>
            <div id="default-tab-content">
              {tabStatus === 'Signing In' && (
                <div className="flex p-4 gap-3 items-center self-stretch rounded-md bg-color-font-200">
                  <div>
                    <img src="assets/info.svg" alt="info" />
                  </div>
                  <div className="flex items-start gap-3">
                    <span className="text-color-font-600 text-sm">Configure ways to sign in</span>
                  </div>
                </div>
              )}
              {tabStatus === 'Device Activity' && (
                <div className="flex p-4 gap-3 items-center self-stretch rounded-md bg-color-font-200">
                  <div>
                    <img src="assets/info.svg" alt="info" />
                  </div>
                  <div className="flex items-start gap-3">
                    <span className="text-color-font-600 text-sm">Sign out of any unfamiliar devices</span>
                  </div>
                </div>
              )}
            </div>
          </div>
          {tabStatus === 'Signing In' && (
            <div className="flex flex-col gap-4">
              <div className="flex flex-col gap-6 p-4 border rounded-lg self-stretch items-start border-bord-white-100">
                <div className="flex items-center gap-2">
                  <div className="p-2 rounded-lg bg-frame-bg-200">
                    <img src="assets/basic_authentication.svg" alt="auth" />
                  </div>
                  <span className="flex text-color-font-600 text-lg font-medium">Basic Authentication</span>
                  {!passwordDetails && (
                    <div className="flex px-2 py-0.5 justify-center items-center gap-1 rounded-xl bg-pending-bg-color-100">
                      <div className="flex w-3 justify-center items-center">
                        <img src="assets/info-pending.svg" alt="pending" />
                      </div>
                      <span className="text-sm text-pending-color-100 font-medium">Password is not setup</span>
                    </div>
                  )}
                </div>
                <div className="flex items-center self-stretch gap-3">
                  <div className="flex flex-col justify-center items-start gap-1 basis-3/4">
                    <span className="flex justify-start items-center font-medium text-base text-color-font-600">Password</span>
                    {passwordDetails && (
                      <div className="flex self-stretch items-start">
                        <span className="font-medium text-xs text-color-font-600">Created On:&nbsp; </span>
                        <span className="font-normal text-xs text-color-font-600">{passwordDate}</span>
                      </div>
                    )}
                  </div>
                  <div className="flex justify-end items-center basis-1/4">
                    <a
                      role="button"
                      href={changePasswordUrl()}
                      target="_blank"
                      className="flex pl-[15px] py-[9px] gap-2 pr-[17px] justify-center items-center rounded-md border border-bord-white-200 shadow-sm"
                    >
                      <img src="assets/update-password.svg" alt="update" />
                      <span className="text-color-font-700 text-sm font-medium">Update Password</span>
                    </a>
                  </div>
                </div>
              </div>
              <div className="grid gap-6 p-4 items-start border border-bord-white-100 rounded-lg">
                <div className="flex gap-2 items-center">
                  <div className="flex p-2 items-start rounded-lg bg-frame-bg-200">
                    <img src="assets/tfa.svg" alt="tfa" />
                  </div>
                  <span className="flex text-color-font-600 text-lg font-medium">Two-Factor Authentication</span>
                  {!otpDetails && (
                    <div className="flex px-2 py-0.5 justify-center items-center gap-1 rounded-xl bg-pending-bg-color-100">
                      <div className="flex w-3 justify-center items-center">
                        <img src="assets/info-pending.svg" alt="pending" />
                      </div>
                      <span className="text-sm text-pending-color-100 font-medium">
                        Authenticator application is not setup
                      </span>
                    </div>
                  )}
                </div>
                <div className="flex gap-1 w-full self-stretch items-center">
                  <div className="flex flex-col basis-2/3 gap-1 items-start">
                    <span className="text-color-font-600 font-medium text-base">Authenticator application</span>
                    {otpDetails && (
                      <div className="flex self-stretch items-start">
                        <span className="font-medium text-xs text-color-font-600">Created On:&nbsp; </span>
                        <span className="font-normal text-xs text-color-font-600">{otpDate}</span>
                      </div>
                    )}
                  </div>
                  <div className="flex justify-end items-center basis-1/3">
                    <a
                      role="button"
                      href={twoFactorAuthorizationUrl()}
                      target="_blank"
                      className="flex pl-[15px] py-[9px] gap-2 pr-[17px] justify-center items-center rounded-md border border-bord-white-200 shadow-sm"
                    >
                      <img src="assets/setup2factorauth.svg" alt="setup" />
                      <span className="text-color-font-700 text-sm font-medium">Set up authenticator application</span>
                    </a>
                  </div>
                </div>
              </div>
            </div>
          )}
          {tabStatus === 'Device Activity' && (
            <div className="flex flex-col gap-4 items-start self-stretch">
              <div className="flex justify-between items-center self-stretch">
                <span className="text-base font-medium text-color-font-600">Signed in devices</span>
                <button
                  className="flex pl-[15px] pr-[17px] py-[9px] justify-center items-center gap-2 rounded-md border border-color-font-300 bg-frame-bg-100"
                  onClick={reloadPage}
                >
                  <div className="flex w-5 p-0.5 justify-center items-center">
                    <img src="assets/refresh-page.svg" alt="refresh" />
                  </div>
                  <span className="text-sm font-medium text-color-font-700">Refresh the page</span>
                </button>
              </div>
              <div className="border self-stretch border-frame-bg-300"></div>
              {sessions.map((session, i) => (
                <div key={session.id} className="flex flex-col gap-4">
                  <div className="flex items-start gap-3 self-stretch">
                    <div className="flex p-2 items-start rounded-lg">
                      <div className="flex items-center justify-center">
                        <img src="assets/signed-in-devices.svg" alt="device" />
                      </div>
                    </div>
                    <div className="flex flex-col items-start self-stretch w-full">
                      <div className="flex py-2 px-3 items-center self-stretch gap-4 justify-between">
                        <div className="flex gap-4 items-center justify-center">
                          <span className="self-stretch text-sm font-medium text-color-font-600">{session.device}</span>
                          <div className="flex flex-col items-start gap-8 bg-frame-bg-100">
                            {session.current_session && (
                              <div className="flex py-0.5 px-3 rounded-xl justify-center items-center bg-success-100">
                                <span className="text-sm font-medium text-success-200">Current Session</span>
                              </div>
                            )}
                          </div>
                        </div>
                        <div className="flex items-start gap-4">
                          <button
                            className="flex py-[9px] pl-[15px] pr-[17px] justify-center items-center gap-2 border border-frame-bg-300 bg-frame-bg-100 rounded-md"
                            onClick={() => signOutOfRequestedSession(i)}
                          >
                            <div className="flex w-5 p-0.5 justify-center items-center">
                              <img className="flex self-stretch" src="assets/sign-out.svg" alt="signout" />
                            </div>
                            <span className="flex text-sm font-medium text-color-font-700">Sign out</span>
                          </button>
                          <button
                            className="flex pl-[17px] pr-[15px] py-[9px] justify-center items-center gap-2 border border-frame-bg-300 bg-frame-bg-100 rounded-md"
                            onClick={() => toggleCollapse(i)}
                          >
                            <span className="text-sm font-medium text-color-font-700">
                              {collapsed[i] ? 'More' : 'Less'}
                            </span>
                            <div className="flex w-5 p-0.5 justify-center items-center">
                              <img
                                className="flex self-stretch"
                                src={collapsed[i] ? 'assets/chevron-down.svg' : 'assets/chevron-up.svg'}
                                alt="toggle"
                              />
                            </div>
                          </button>
                        </div>
                      </div>
                      {!collapsed[i] && (
                        <div className="flex items-start self-stretch">
                          <div className="flex flex-col items-start">
                            <div className="flex px-3 py-4 items-center self-stretch gap-2">
                              <div className="flex flex-col items-start">
                                <span className="text-sm font-medium text-color-font-600">IP Address</span>
                                <span className="text-sm font-normal text-color-font-500">{session.ip}</span>
                              </div>
                            </div>
                            <div className="flex px-3 py-4 items-center self-stretch gap-2">
                              <div className="flex flex-col items-start">
                                <span className="text-sm font-medium text-color-font-600">Started</span>
                                <span className="text-sm font-normal text-color-font-500">{session.started}</span>
                              </div>
                            </div>
                          </div>
                          <div className="flex flex-col items-start">
                            <div className="flex px-3 py-4 items-center self-stretch gap-2">
                              <div className="flex flex-col items-start">
                                <span className="text-sm font-medium text-color-font-600">Last Accessed</span>
                                <span className="text-sm font-normal text-color-font-500">{session.last_accessed}</span>
                              </div>
                            </div>
                            <div className="flex px-3 py-4 items-center self-stretch gap-2">
                              <div className="flex flex-col items-start">
                                <span className="text-sm font-medium text-color-font-600">Expires</span>
                                <span className="text-sm font-normal text-color-font-500">{session.expires}</span>
                              </div>
                            </div>
                          </div>
                          <div className="flex flex-col items-start">
                            <div className="flex px-3 py-4 items-center self-stretch gap-2">
                              <div className="flex flex-col items-start">
                                <span className="text-sm font-medium text-color-font-600">Clients</span>
                                <span className="text-sm font-normal text-color-font-500">
                                  {session.clients.join(', ')}
                                </span>
                              </div>
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  </div>
                  <div className="border self-stretch border-frame-bg-300"></div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
      <div className="flex py-6 px-4 items-center justify-between border-t border-color-font-300 sticky bottom-0 bg-frame-bg-100 shadow-[0_-1px_0px_0px_rgba(0,0,0,0.08)] w-savebar">
        <div className="flex basis-full items-center justify-end gap-3">
          <button className="flex px-[17px] py-[9px] justify-center items-center rounded-md border border-bord-white-200 shadow-sm">
            <a href="" className="text-sm text-color-font-700 font-medium">
              Cancel
            </a>
          </button>
          <button
            type="submit"
            className="flex px-[17px] py-[9px] justify-center items-center rounded-md bg-delhivery-color-100 shadow-sm"
            onClick={onSave}
          >
            <span className="text-sm text-color-font-100 font-medium">Save</span>
          </button>
        </div>
      </div>
    </div>
  );
};

