import { useEffect, useState, useCallback } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useHeaderConfig } from '../context/HeaderConfigContext';
import { loginService } from '../services/login.service';
import { UserDropdown } from './UserDropdown';
import { Breadcrumb } from './Breadcrumb';
import { NavigationItems } from './NavigationItems';

export const Header = () => {
    const { isAuthenticated, isLoading } = useAuth();
    const { headerConfig } = useHeaderConfig();
    const [firstName, setFirstName] = useState('');
    const [lastName, setLastName] = useState('');
    const [email, setEmail] = useState('');

    // Check if user is logged in (matching Angular's isLoggedIn logic)
    const isLoggedIn = () => {
        return loginService.hasValidAccessToken() || !!sessionStorage.getItem('access_token');
    };

    const populateFormFromServer = useCallback(async () => {
        const issuer = sessionStorage.getItem('issuer');
        if (issuer) {
            // Ensure token is available before making request
            const token = sessionStorage.getItem('access_token');
            if (!token) {
                console.warn('[Header] No access token available, skipping account fetch');
                return;
            }

            try {
                const accountUrl = issuer.startsWith('http')
                    ? issuer.replace(/^https?:\/\/[^/]+/, '') + '/account'
                    : `${issuer}/account`;

                const response = await axios.get<{
                    username: string;
                    firstName: string;
                    lastName: string;
                    email: string;
                }>(accountUrl);
                setFirstName(response.data.firstName);
                setLastName(response.data.lastName || '');
                setEmail(response.data.email);
            } catch (error: any) {
                console.error('Error fetching user data:', error);
                if (error.response?.status === 401) {
                    console.error('[Header] 401 Unauthorized');
                    console.error('[Header] Token exists:', !!sessionStorage.getItem('access_token'));
                    console.error('[Header] Request URL:', `${issuer}/account`);
                }
            }
        }
    }, []);

    useEffect(() => {
        // Wait for auth to finish initializing before making API calls
        // This prevents 401 errors on page reload
        if (isLoading) {
            return;
        }

        if (isLoggedIn()) {
            populateFormFromServer();
        } else {
            // Subscribe to token events like Angular does
            const userManager = loginService.getUserManager();
            if (userManager) {
                const handleUserLoaded = () => {
                    populateFormFromServer();
                };

                userManager.events.addUserLoaded(handleUserLoaded);
                userManager.events.addAccessTokenExpiring(() => {
                    // Token is expiring, will be refreshed automatically
                });

                return () => {
                    userManager.events.removeUserLoaded(handleUserLoaded);
                };
            }
        }
    }, [isAuthenticated, isLoading, populateFormFromServer]); // Include isLoading to wait for auth init



    // Match Angular's *ngIf="isLoggedIn()" check
    if (!isLoggedIn()) {
        return null;
    }

    return (
        <div>
            <nav className="bg-white">
                <div className="flex items-center justify-between self-stretch w-full border-b border-color-font-300">
                    <div className="h-16 flex items-center gap-6">
                        <div className="flex items-start border-r border-color-font-300 pt-4 pb-3.5 max-w-64 h-auto">
                            <div className="flex justify-center items-center gap-2 self-stretch px-6 w-full">
                                <div className="flex pt-[5px] pb-[4.12px] justify-center items-center">
                                    <a href="/">
                                        <img
                                            className="h-6 w-36"
                                            src={headerConfig?.logoSrc || 'assets/Logo.svg'}
                                            alt={headerConfig?.logoAlt || 'Delhivery'}
                                        />
                                    </a>
                                </div>
                            </div>
                        </div>
                        <div className="flex items-center">
                            <span className="text-2xl font-black text-gray-900 flex font-sans leading-relaxed">
                                {headerConfig?.title}
                            </span>
                        </div>
                        <Breadcrumb />
                    </div>
                    <div className="flex items-center justify-between pl-[13px]">

                        <div className="flex items-center justify-end gap-2.5">
                            {headerConfig?.navItems && headerConfig?.navItems?.length > 0 ? <NavigationItems navItems={headerConfig?.navItems} /> : null}

                            {headerConfig?.otherComponent ?
                                <div className="flex items-center">{headerConfig.otherComponent}</div> : null}
                            <UserDropdown firstName={firstName} lastName={lastName} email={email} />
                        </div>
                    </div>
                </div>
            </nav>
        </div>
    );
};

