import { useLocation } from 'react-router-dom';
import type { HeaderConfig } from '../types';

interface NavigationItemsProps {
  navItems?: HeaderConfig['navItems'];
}

export const NavigationItems = ({ navItems }: NavigationItemsProps) => {
  const location = useLocation();

  const isActiveRoute = (route: string) => {
    return location.pathname === route;
  };

  if (!navItems || navItems.length === 0) {
    return null;
  }

  return (
    <div className="flex items-center justify-center gap-4">
      {navItems.map((item) => (
        <a
          key={item.route}
          href={item.route}
          className={`text-sm font-bold px-4 py-2 text-color-font-600 font-sans transition-all duration-200 border rounded-md ${isActiveRoute(item.route)
              ? 'text-red-600 border-red-600 bg-red-50'
              : 'text-color-font-600 border-transparent hover:border-color-font-300 hover:bg-gray-200'
            }`}
        >
          {item.label}
        </a>
      ))}
    </div>
  );
};

