import { UserManager } from 'oidc-client-ts';
import { oidcConfigService } from './oidc.config';
import { configService } from './config.service';
import { setGlobalUserManager, setLoginFunctions } from './auth.interceptor';

class LoginService {
    private userManager: UserManager | null = null;

    loadDiscoveryDocument = async () => {
        const issuer = sessionStorage.getItem('issuer') ?? configService.default_issuer;
        const clientId = configService.clientId;
        const url = new URL(window.location.href);
        const baseUri = url.host;
        const proto = url.protocol;
        const redirectUri = `${proto}//${baseUri}/lib-auth-oauth-callback`;
        const configOptions = oidcConfigService.configOptions(issuer, clientId, redirectUri);

        this.userManager = new UserManager(configOptions);
        setGlobalUserManager(this.userManager);
        await this.userManager.metadataService.getMetadata();

        // Check if user is already logged in and store access_token
        const user = await this.userManager.getUser();
        if (user && user.access_token) {
            sessionStorage.setItem('access_token', user.access_token);
        }
    };

    configureSSO = async (issuer: string, clientId: string, redirectUri: string) => {
        const configOptions = oidcConfigService.configOptions(issuer, clientId, redirectUri);
        sessionStorage.setItem('issuer', issuer);

        this.userManager = new UserManager(configOptions);
        setGlobalUserManager(this.userManager);

        await this.userManager.metadataService.getMetadata();
        const user = await this.userManager.getUser();

        if (user && user.access_token) {
            const accessToken = user.access_token;
            if (accessToken) {
                sessionStorage.setItem('access_token', accessToken);
            }
        } else {
            console.error('No valid AT');
            await this.userManager.signinRedirect();
        }
    };

    login = async (issuer: string, clientId: string, redirectUri: string) => {
        localStorage.setItem('loginInitiated', 'true');
        await this.configureSSO(issuer, clientId, redirectUri);
    };

    clearStorage = () => {
        sessionStorage.clear();
        localStorage.clear();
        window.location.href = '/';
    }

    logout = async () => {
        try {
        const issuer = sessionStorage.getItem('issuer') || configService.default_issuer;
        const oidcStorageKey = `oidc.user:${issuer}:`;
        const storedUserData = sessionStorage.getItem(oidcStorageKey);

        if (this.userManager && storedUserData && issuer) {
            const userData = JSON.parse(storedUserData);
            await this.userManager.signoutRedirect({
                id_token_hint: userData.id_token,
            });
            this.clearStorage();
            return; // Exit early if successful
        } else if (this.userManager) {
            await this.userManager?.signoutRedirect();
            this.clearStorage();
            return; // Exit early if successful
        } else {
            console.error('No user manager found! Cannot logout.');
            this.clearStorage();
                return; // Exit early if successful
            }
        } catch (error) {
            console.error('Logout error:', error);
            this.clearStorage();
            return; // Exit early if successful
        }
    };


    getUserManager = () => {
        return this.userManager;
    };

    setUserManager = (manager: UserManager) => {
        this.userManager = manager;
        setGlobalUserManager(manager);
    };

    getAccessToken = async (): Promise<string | null> => {
        if (this.userManager) {
            try {
                const user = await this.userManager.getUser();
                if (user?.access_token) {
                    return user.access_token;
                }
            } catch (error) {
                // Fallback to sessionStorage
            }
        }

        // Fallback to sessionStorage (matching Angular's logic)
        return sessionStorage.getItem('access_token');
    };

    hasValidAccessToken = (): boolean => {
        // Check sessionStorage first (matching Angular's hasValidAccessToken logic)
        const token = sessionStorage.getItem('access_token');
        if (token) return true;

        // Check oidc-client-ts storage
        if (this.userManager) {
            // This is async, but for sync check we use sessionStorage
            return false;
        }

        return false;
    };
}

export const loginService = new LoginService();

// Register functions with interceptor to avoid circular dependency
setLoginFunctions(
    (issuer: string, clientId: string, redirectUri: string) => loginService.login(issuer, clientId, redirectUri)
);

