import type { AuthConfig } from '../types';

class ConfigService {
  #clientId: string = '';
  #landing_page: string = '';
  #default_issuer: string = '';

  setConfig(config: AuthConfig): void {
    this.#clientId = config.clientId;
    this.#landing_page = config.landing_page;
    this.#default_issuer = config.default_issuer;
  }

  set clientId(clientId: string) {
    this.#clientId = clientId;
  }

  get clientId(): string {
    return this.#clientId;
  }

  set landing_page(landing_page: string) {
    this.#landing_page = landing_page;
  }

  get landing_page(): string {
    // Default to '/' if not set
    return this.#landing_page || '/';
  }

  set default_issuer(default_issuer: string) {
    this.#default_issuer = default_issuer;
  }

  get default_issuer(): string {
    return this.#default_issuer;
  }
}

export const configService = new ConfigService();

