import { useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { UserManager } from 'oidc-client-ts';
import { useAuth } from '../context/AuthContext';
import { loginService } from '../services/login.service';
import { configService } from '../services/config.service';
import { oidcConfigService } from '../services/oidc.config';
import { setGlobalUserManager } from '../services/auth.interceptor';

export const OAuthCallback = () => {
  const navigate = useNavigate();
  const { getUserManager } = useAuth();
  const processedRef = useRef(false);

  useEffect(() => {
    // Prevent multiple executions
    if (processedRef.current) return;

    const handleCallback = async () => {
      processedRef.current = true;

      const issuer = sessionStorage.getItem('issuer');
      if (!issuer) {
        console.error('Unable to find issuer.');
        const landingPage = configService.landing_page || '/';
        await navigate(landingPage.startsWith('/') ? landingPage : `/${landingPage}`);
        return;
      }

      let userManager = getUserManager() || loginService.getUserManager();

      // If UserManager doesn't exist, create one (matching Angular's auth.component.ts pattern)
      if (!userManager) {
        const url = new URL(window.location.href);
        const baseUri = url.host;
        const proto = url.protocol;
        const clientId = configService.clientId;
        const redirectUri = `${proto}//${baseUri}/lib-auth-oauth-callback`;
        const configOpts = oidcConfigService.configOptions(issuer, clientId, redirectUri);

        userManager = new UserManager(configOpts);
        loginService.setUserManager(userManager);
      }

      try {
        // Load discovery document and process callback (matching Angular's loadDiscoveryDocumentAndTryLogin)
        await userManager.metadataService.getMetadata();
        const user = await userManager.signinRedirectCallback();

        if (user && user.access_token) {
          // Store access_token in sessionStorage (matching ums-auth behavior)
          sessionStorage.setItem('access_token', user.access_token);
          // Update global UserManager reference
          setGlobalUserManager(userManager);
          // Clear login initiated flag
          localStorage.removeItem('loginInitiated');
        }

        // Navigate to landing page (matching Angular's router.navigate)
        // Use window.location to trigger full page reload so auth state updates
        const landingPage = configService.landing_page || '/';
        window.location.href = landingPage.startsWith('/') ? landingPage : `/${landingPage}`;
      } catch (error) {
        console.error('OAuth callback error:', error);
        localStorage.removeItem('loginInitiated');
        const landingPage = configService.landing_page || '/';
        window.location.href = landingPage.startsWith('/') ? landingPage : `/${landingPage}`;
      }
    };

    void handleCallback();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Empty deps - only run once on mount

  return null;
};
