import { useLocation } from 'react-router-dom';

interface BreadcrumbItem {
    label: string;
    path: string;
}

interface BreadcrumbProps {
    items?: BreadcrumbItem[];
}

export const Breadcrumb = ({ items }: BreadcrumbProps) => {
    const location = useLocation();

    // Default breadcrumb for user profile page
    if (location.pathname === '/lib-user-profile') {
        return (
            <div className="flex items-center pl-8 pr-6">
                <div className="flex items-center justify-center gap-4">
                    <a
                        href="/lib-user-profile"
                        className="text-sm font-medium hover:text-blue-600 text-color-font-600"
                    >
                        Personal Info
                    </a>
                    <div className="self-stretch">
                        <img src="assets/breadcrumb.svg" alt="breadcrumb-arrow" />
                    </div>
                </div>
            </div>
        );
    }

    // Custom breadcrumb items if provided
    if (items && items.length > 0) {
        return (
            <div className="flex items-center px-6">
                <div className="flex items-center justify-center gap-4">
                    {items.map((item, index) => (
                        <div key={item.path} className="flex items-center gap-4">
                            <a
                                href={item.path}
                                className="text-sm font-medium hover:text-blue-600 text-color-font-600"
                            >
                                {item.label}
                            </a>
                            {index < items.length - 1 && (
                                <div className="self-stretch">
                                    <img src="assets/breadcrumb.svg" alt="breadcrumb-arrow" />
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    // No breadcrumb to show
    return null;
};

